import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Exercise {
  name: string;
  sets: number;
  reps: string | number;
  rest: string;
}

interface WorkoutData {
  todayWorkout: {
    exercises: Exercise[];
  };
}

export default function Widget() {
  const workoutData = response.data as WorkoutData;
  const exercises = workoutData.todayWorkout.exercises;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#333' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722', mb: 1 }}>
              Today's Workout
            </Typography>
            <Stack spacing={1.5}>
              {exercises.map((exercise, index) => (
                <Box key={index}>
                  <Typography variant="body1" sx={{ color: '#FFC107', fontWeight: 500 }}>
                    {exercise.name}
                  </Typography>
                  <Stack direction="row" spacing={0.5} sx={{ mt: 0.5 }}>
                    <Chip label={`Sets: ${exercise.sets}`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#555', color: '#FFC107' }} />
                    <Chip label={`Reps: ${exercise.reps}`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#555', color: '#FFC107' }} />
                    <Chip label={`Rest: ${exercise.rest}`} sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#555', color: '#FFC107' }} />
                  </Stack>
                </Box>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
